python -c "
from outlines.prompts import register_filter, unregister_filter, prompt

# Global filter
register_filter('shout', str.upper)

@prompt
def greet(text):
    '{{ text | shout }}'
print('global only:', greet('hello'))

# Local filter overriding global
@prompt(filters={'shout': lambda s: s + '!!!'})
def greet2(text):
    '{{ text | shout }}'
print('local overrides global:', greet2('hello'))

unregister_filter('shout')
try:
    greet('hello')
except Exception as e:
    print('after unregister, new template fails as expected:', type(e).__name__)
"
